package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// It implements the pipeline: aliyun ... | jq ... > outputFile
// safely without using shell execution to prevent injection attacks.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Prepare the output file
	outfile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outfile.Close()

	// 2. Configure the 'aliyun' command
	// We pass arguments as a slice. This prevents shell injection because
	// the arguments are passed directly to the kernel, not parsed by a shell.
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 3. Configure the 'jq' command
	cmdJQ := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 4. Set up the pipeline: cmdAliyun Stdout -> cmdJQ Stdin
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmdJQ.Stdin = pipe

	// 5. Set up output: cmdJQ Stdout -> Output File
	cmdJQ.Stdout = outfile

	// 6. Capture Stderr for debugging
	// We capture stderr from both commands to return useful error messages if something fails.
	var stderrBuf bytes.Buffer
	cmdAliyun.Stderr = &stderrBuf
	cmdJQ.Stderr = &stderrBuf

	// 7. Start the commands
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := cmdJQ.Start(); err != nil {
		// If jq fails to start, ensure we don't leave aliyun running or zombie
		_ = cmdAliyun.Process.Kill() 
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// 8. Wait for completion
	// Wait for the producer (aliyun) first
	errAliyun := cmdAliyun.Wait()
	// Then wait for the consumer (jq)
	errJQ := cmdJQ.Wait()

	// Check for errors
	if errAliyun != nil {
		return stderrBuf.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", errAliyun, stderrBuf.String())
	}
	if errJQ != nil {
		return stderrBuf.String(), fmt.Errorf("jq command failed: %w, stderr: %s", errJQ, stderrBuf.String())
	}

	return "Command executed successfully", nil
}

func main() {
	// Example usage
	msg, err := QuerySLBAndExport("lb-example-name", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Println(msg)
}

