package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
//
// Security Fixes:
// 1. Removed "sh -c" to prevent Command Injection via shell metacharacters.
// 2. Used exec.Command with individual arguments to ensure input is treated as data.
// 3. Handled pipes and file redirection using Go's standard library.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate and clean the file path to prevent basic path traversal issues
	cleanPath := filepath.Clean(outputFile)

	// Create the output file using Go's os package.
	// This prevents shell injection via the filename (e.g., if outputFile was "file; rm -rf /")
	outfile, err := os.Create(cleanPath)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outfile.Close()

	// Construct the commands separately.
	// The arguments are passed directly to the syscall, not parsed by a shell.

	// Command 1: aliyun slb DescribeLoadBalancers --LoadBalancerName <name>
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Command 2: jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect the stdout of aliyun to the stdin of jq
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// Redirect the stdout of jq directly to the file
	cmdJq.Stdout = outfile

	// Capture stderr from both commands to return in case of error
	var stderrBuf bytes.Buffer
	cmdAliyun.Stderr = &stderrBuf
	cmdJq.Stderr = &stderrBuf

	// Start the first command (aliyun)
	if err := cmdAliyun.Start(); err != nil {
		return stderrBuf.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the second command (jq)
	if err := cmdJq.Start(); err != nil {
		return stderrBuf.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for the first command to finish writing to the pipe
	if err := cmdAliyun.Wait(); err != nil {
		return stderrBuf.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for the second command to finish writing to the file
	if err := cmdJq.Wait(); err != nil {
		return stderrBuf.String(), fmt.Errorf("jq command failed: %w", err)
	}

	return fmt.Sprintf("Successfully exported SLB data to %s", cleanPath), nil
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("lb-example-123", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\nDetails: %s\n", err, result)
		return
	}
	fmt.Println(result)
}

