package main

import (
	"fmt"
	"os/exec"
)

// QuerySLBAndExport executes a shell pipeline to query Aliyun SLB information and export specific fields using jq.
//
// It constructs the equivalent of:
// aliyun slb DescribeLoadBalancers --LoadBalancerName $1 | jq '.LoadBalancers.LoadBalancer[]' > $2
//
// Parameters:
//   - loadBalancerName: The ID or Name of the Load Balancer to query.
//   - outputFile: The path to the file where the JSON output will be saved.
//
// Returns:
//   - string: The combined standard output and standard error from the shell execution (useful for debugging).
//   - error: An error if the command execution fails.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// We use "sh -c" to execute the pipeline.
	// To ensure security and prevent shell injection, we do not concatenate the variables directly into the string.
	// Instead, we pass them as positional arguments ($1, $2) to the shell command.
	//
	// $0 is set to "slb_query_script" (process name for the shell)
	// $1 is mapped to loadBalancerName
	// $2 is mapped to outputFile
	shellScript := `aliyun slb DescribeLoadBalancers --LoadBalancerName "$1" | jq '.LoadBalancers.LoadBalancer[]' > "$2"`

	cmd := exec.Command("sh", "-c", shellScript, "slb_query_script", loadBalancerName, outputFile)

	// Execute the command and capture combined output (stdout + stderr).
	// Note: Since we are redirecting stdout to a file in the shell script using '>',
	// the returned 'output' variable will primarily contain stderr (errors/warnings)
	// or output from jq if the redirection fails.
	output, err := cmd.CombinedOutput()
	if err != nil {
		return string(output), fmt.Errorf("failed to execute command pipeline: %w", err)
	}

	return string(output), nil
}

func main() {
	// Example configuration
	lbName := "lb-bp1234567890abcdef"
	outFile := "output.json"

	fmt.Printf("Starting export for LoadBalancer: %s\n", lbName)

	// Invoke the function
	resultOutput, err := QuerySLBAndExport(lbName, outFile)

	if err != nil {
		fmt.Printf("Error occurred: %v\n", err)
		if len(resultOutput) > 0 {
			fmt.Printf("Command Output/Log: %s\n", resultOutput)
		}
		return
	}

	fmt.Printf("Success! Data exported to %s\n", outFile)
}

