	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// 2. Configure the 'aliyun' command
	// We pass arguments as separate strings. This prevents shell injection because
	// the OS treats loadBalancerName as a raw string argument, not code.
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 3. Configure the 'jq' command
	cmdJQ := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 4. Set up the pipeline: aliyun stdout -> jq stdin
	aliyunStdout, err := cmdAliyun.StdoutPipe()
