	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Set up the pipe between aliyun (stdout) and jq (stdin)
	// cmdAliyun.StdoutPipe returns a ReadCloser that reads from the command's stdout.
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}
	cmdJq.Stdin = pipe

	// 4. Set up the output file
	// We open (or create/truncate) the file in Go and attach it to jq's stdout.
	f, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file '%s': %w", outputFile, err)
	}
	defer f.Close()
	cmdJq.Stdout = f

	// Optional: Capture stderr to console for debugging purposes
	cmdAliyun.Stderr = os.Stderr
	cmdJq.Stderr = os.Stderr

	// 5. Start the commands
	// We must start the producer (aliyun) and consumer (jq) before waiting.
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := cmdJq.Start(); err != nil {
