	if err := cmdAliyun.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command returned error: %w", err)
	}

	// Wait for the consumer to finish processing the data.
	if err := cmdJq.Wait(); err != nil {
		return "", fmt.Errorf("jq command returned error: %w", err)
	}

	return fmt.Sprintf("Successfully exported SLB information to %s", outputFile), nil
}

