package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// It uses native os/exec piping to avoid shell injection vulnerabilities.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create (or truncate) the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Prepare the aliyun command.
	// We pass arguments individually. This prevents shell injection because
	// the OS treats 'loadBalancerName' strictly as an argument, not a shell command.
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Prepare the jq command.
	// Note: We do not need to wrap the filter in single quotes like in bash;
	// exec passes the string directly to the process.
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun stdout -> jq stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	jqCmd.Stdin = aliyunStdout

	// Redirect jq stdout -> file
	jqCmd.Stdout = outFile

	// Capture stderr from both commands to assist in debugging if something goes wrong
	var stderrBuf bytes.Buffer
	aliyunCmd.Stderr = &stderrBuf
	jqCmd.Stderr = &stderrBuf

	// Start jq first; it will wait for input from the pipe
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	// Run aliyun command. Run() starts the command and waits for it to complete.
	// When aliyun finishes, it closes the pipe, sending EOF to jq.
	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// Wait for jq to finish processing the data and writing to the file
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, stderrBuf.String())
	}

	return fmt.Sprintf("Command executed successfully. Output saved to %s", outputFile), nil
}

func main() {
	// Example usage
	output, err := QuerySLBAndExport("lb-bp1example", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Println(output)
}

