// filters it using jq, and saves the output to a file.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// We need to construct the full command line string.
	// Note: Since this involves pipes (|) and redirection (>), we cannot call the binaries directly
	// via exec.Command without a shell. We must use "sh -c" (or "bash -c") to interpret the pipeline.

