		loadBalancerName,
		outputFile,
	)

	// Create the command structure
	cmd := exec.Command("sh", "-c", cmdStr)

	// Execute the command. CombinedOutput captures both stdout and stderr.
	// Since stdout is redirected to a file in the command string, the returned output
	// will primarily contain any error messages generated by the tools.
	output, err := cmd.CombinedOutput()

	return string(output), err
}

func main() {
