package main

import (
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to query SLB details,
// pipes the output to jq for formatting, and writes the result to a file.
//
// Equivalent shell command:
// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Prepare the output file
	// We open/create the file here to handle file system errors early.
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file '%s': %w", outputFile, err)
	}
	defer outFile.Close()

	// 2. Configure the 'aliyun' command
	// We pass arguments individually to avoid shell injection risks.
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 3. Configure the 'jq' command
	// Note: We do not need to wrap the filter in single quotes as we would in bash;
	// exec.Command passes the argument directly to the binary.
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 4. Set up the pipeline
	// Get the stdout pipe from the aliyun command to feed into jq's stdin.
	aliyunStdout, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun command: %w", err)
	}

	// Connect aliyun output to jq input
	cmdJq.Stdin = aliyunStdout
	// Connect jq output to the file
	cmdJq.Stdout = outFile

	// Optional: Connect stderr to the parent process stderr so the user sees CLI errors
	cmdAliyun.Stderr = os.Stderr
	cmdJq.Stderr = os.Stderr

	// 5. Execution
	// Start the aliyun command (don't wait for it yet)
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Run the jq command. Run() starts the command and waits for it to complete.
	// Since jq reads from aliyun's pipe, it will consume data as aliyun produces it.
	if err := cmdJq.Run(); err != nil {
		return "", fmt.Errorf("failed to execute jq command: %w", err)
	}

	// Finally, ensure the aliyun command finished successfully.
	if err := cmdAliyun.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command finished with error: %w", err)
	}

	return fmt.Sprintf("Successfully exported SLB data to %s", outputFile), nil
}

func main() {
	// Example usage
	// In a real scenario, these might come from command line flags (e.g., os.Args)
	lbName := "lb-example-id"
	outFile := "output.json"

	fmt.Printf("Processing Load Balancer: %s...\n", lbName)

	result, err := QuerySLBAndExport(lbName, outFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(result)
}

