package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// It uses native os/exec piping instead of shell execution for security.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" || outputFile == "" {
		return "", fmt.Errorf("loadBalancerName and outputFile cannot be empty")
	}

	// 1. Prepare the 'aliyun' command
	// We pass arguments directly to exec.Command, preventing shell injection.
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 2. Prepare the 'jq' command
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Create the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// 4. Set up the pipeline
	// Connect aliyun stdout to jq stdin
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// Connect jq stdout to the file
	cmdJq.Stdout = outFile

	// Capture stderr from both commands for debugging purposes
	var stderr bytes.Buffer
	cmdAliyun.Stderr = &stderr
	cmdJq.Stderr = &stderr

	// 5. Start the commands
	// Start aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return stderr.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := cmdJq.Start(); err != nil {
		return stderr.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// 6. Wait for completion
	// Wait for aliyun to finish writing to the pipe
	if err := cmdAliyun.Wait(); err != nil {
		return stderr.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq to finish processing and writing to file
	if err := cmdJq.Wait(); err != nil {
		return stderr.String(), fmt.Errorf("jq command failed: %w", err)
	}

	return fmt.Sprintf("Successfully exported SLB info to %s", outputFile), nil
}

func main() {
	// Example usage
	output, err := QuerySLBAndExport("lb-bp1...", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\nOutput/Stderr: %s\n", err, output)
		return
	}
	fmt.Println(output)
}

