// QuerySLBAndExport executes a shell command pipeline to query Aliyun SLB info,
// filter it with jq, and save it to a file.
//
// Target command:
// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic validation to prevent generating invalid shell commands
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Construct the command string.
	// We use "sh -c" to leverage the shell's native piping (|) and redirection (>) capabilities.
	// Note: In a production environment dealing with untrusted input, strict validation
	// should be applied to loadBalancerName and outputFile to prevent Shell Injection attacks.
	commandStr := fmt.Sprintf(
		"aliyun slb DescribeLoadBalancers --LoadBalancerName %s | jq '.LoadBalancers.LoadBalancer[]' > %s",
		loadBalancerName,
		outputFile,
	)

	// Create the command structure
	cmd := exec.Command("sh", "-c", commandStr)

	// Execute the command and capture combined standard output and standard error.
	// Note that since we are redirecting stdout to a file using '>', the 'output' variable
	// here will primarily contain stderr or empty string on success, unless the shell itself prints something.
	output, err := cmd.CombinedOutput()
	if err != nil {
		return string(output), fmt.Errorf("command execution failed: %w", err)
	}

	return string(output), nil
}

func main() {
	// Example usage configuration
	lbName := "lb-example-id"
	outFile := "output.json"

	fmt.Printf("Starting export for Load Balancer: %s to %s\n", lbName, outFile)

	// Execute the function
