package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// pipes the output to jq for formatting, and saves it to the specified file.
// This implementation avoids shell injection by executing commands directly
// and handling pipes within Go.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Create the output file (replaces shell redirection '>')
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// 2. Configure the 'aliyun' command
	// We pass arguments individually to exec.Command to prevent shell injection.
	// Command: aliyun slb DescribeLoadBalancers --LoadBalancerName <name>
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 3. Configure the 'jq' command
	// Logic: aliyun stdout -> jq stdin
	// Command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 4. Set up the pipe
	// Get the stdout pipe from the aliyun command
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	// Connect it to jq's stdin
	jqCmd.Stdin = aliyunStdout

	// 5. Redirect jq's stdout to the file
	jqCmd.Stdout = outFile

	// 6. Capture stderr from both commands for error reporting
	var stderrBuf bytes.Buffer
	aliyunCmd.Stderr = &stderrBuf
	jqCmd.Stderr = &stderrBuf

	// 7. Start the commands
	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		// Attempt to kill aliyun process if jq fails to start to prevent zombies
		_ = aliyunCmd.Process.Kill()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// 8. Wait for completion
	// Wait for aliyun to finish. This closes the pipe to jq, sending EOF.
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// Wait for jq to finish processing the stream and writing to file.
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, stderrBuf.String())
	}

	return fmt.Sprintf("Command executed successfully. Output saved to %s", outputFile), nil
}

func main() {
	// Example usage
	output, err := QuerySLBAndExport("lb-example-id", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Println(output)
}

